const j = $json; const userPrompt = `Use the following input variables to generate the LinkedIn content pack.

RAW CONTEXT
${j.raw_context}

OPTIONAL GOAL
${j.optional_goal || 'auto'}

OPTIONAL AUDIENCE
${j.optional_audience || 'auto'}

OPTIONAL CTA STYLE
${j.optional_cta_style || 'auto'}

SOURCE TYPE
${j.source_type || 'unknown'}

PROJECT TITLE
${j.project_title || ''}

PROJECT STACK
${j.project_stack || ''}

PROJECT LINK
${j.project_link || ''}

EXTRA NOTES
${j.extra_notes || ''}

INSTRUCTIONS
- Choose the best mode automatically unless optional_goal explicitly specifies one.
- If the input is GitHub, README, architecture, or project-documentation heavy, strongly prefer Mode B.
- If the input is career-facing, milestone-facing, or recruiter-signal heavy, strongly prefer Mode A.
- Otherwise use Mode C.
- Keep the writing technically credible and practical.
- Do not overclaim.
- Return JSON only.`; return [{ json: { ...j, user_prompt: userPrompt } }];
